// ── FUENTES DE DATOS ──
const agenteOutput = $('Agente Pedidos').first()?.json?.output ?? '';
const datosUsuario = {
  from:        $('Extractormensajes').first().json.from,
  idMensajero: $('Extractormensajes').first().json['id mensajero'],
  profilename: $('Extractormensajes').first().json.profile_name ?? 'Cliente',
  idMensaje:   $('Extractormensajes').first().json['id cliente'],
};

// ── GUARDIA ──
if (!agenteOutput || agenteOutput.trim().length === 0) {
  return [{ json: { output: 'Lo siento, no pude procesar tu mensaje.', totalfinal: 0, from: datosUsuario.from, 'id mensajero': datosUsuario.idMensajero }}];
}

// ── DETECCIÓN CONFIRMACIÓN ESTRICTA ──
const textoUsuario = $('Extractormensajes').first().json.text?.body ?? '';
const esConfirmacion = /\bconfirm[oa]\b/i.test(textoUsuario);

// Si el cliente NO ha dicho "confirmo", forzamos a que no vaya a la DB (totalfinal = 0)
if (!esConfirmacion) {
    return [{ json: {
        output: agenteOutput,
        totalfinal: 0,  // <-- ESTE ES EL FRENO DE MANO
        from: datosUsuario.from,
        'id mensajero': datosUsuario.idMensajero,
        id: datosUsuario.idMensaje
    }}];
}

// SI DIJO CONFIRMO, extraemos el JSON puro que generó la IA:
let datosParsed = null;
let metodo = 'FALL';

const matchJSON = agenteOutput.match(/\{[\s\S]*?\}/);
if (matchJSON) {
    try {
        datosParsed = JSON.parse(matchJSON[0]);
        metodo = 'JSON_EXTRAIDO';
    } catch(e) {}
}

const totalFinal = parseFloat(datosParsed?.total ?? 0) || 0;
const pedidoFinal = datosParsed?.pedido ?? 'Pedido sin detallar';

// Ocultamos el JSON del mensaje que verá el cliente
const outputFinal = agenteOutput.replace(/\{[\s\S]*?\}/g, '').trim() || '¡Perfecto! Procesando tu orden...';

return [{ json: {
  output:           outputFinal,
  nombre: datosParsed?.nombre || "⚠️ CLIENTE POR IDENTIFICAR",
  direccion:        datosParsed?.direccion ?? 'No especificada',
  metodopago:       datosParsed?.metodopago   ?? 'Efectivo',
  tiposervicio:     datosParsed?.tiposervicio  ?? 'Recojo',
  pedidodetallado:  pedidoFinal,
  total:            totalFinal,
  totalfinal:       totalFinal, // Ahora sí va a la DB
  telefono:         datosParsed?.telefono  ?? datosUsuario.from,
  metodoextraccion: metodo,
  from:             datosUsuario.from,
  'id mensajero':   datosUsuario.idMensajero,
  id:               datosUsuario.idMensaje,
}}];

// Obtener la respuesta del agente Detector
const respuesta = $json.output.toLowerCase();

// Palabras clave que indican modificación de pedido
const palabrasModificar = [
  'modificar', 'cambiar', 'añadir', 'agregar',
  'actualizar', 'editar', 'quiero', 'comprar',
  'pedir', 'delivery', 'pedido', 'orden'
];

// Palabras clave que indican solo consulta
const palabrasConsultar = [
  'estado', 'consultar', 'saber', 'información',
  'cuánto falta', '¿cómo va', 'avance'
];

// Contar coincidencias
let puntosModificar = 0;
let puntosConsultar = 0;

palabrasModificar.forEach(palabra => {
  if (respuesta.includes(palabra)) puntosModificar++;
});

palabrasConsultar.forEach(palabra => {
  if (respuesta.includes(palabra)) puntosConsultar++;
});

// Decidir la acción
let accion;
if (puntosModificar > puntosConsultar) {
  accion = "MODIFICAR";
} else if (puntosConsultar > 0) {
  accion = "CONSULTAR";
} else {
  // Por defecto, si no está claro, asumir modificación
  accion = "MODIFICAR";
}

// Retornar resultado
return {
  json: {
    output: $json.output,
    accion: accion,
    puntos_modificar: puntosModificar,
    puntos_consultar: puntosConsultar,
    respuesta_original: respuesta
  }
};

